import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;

public class FileHandler {
    private static final String BASE_DIRECTORY = "/path/to/directory/";

    public static void readFile(String fileName) {
        try {
            File file = new File(BASE_DIRECTORY + fileName);
            if (file.getCanonicalPath().startsWith(new File(BASE_DIRECTORY).getCanonicalPath())) {
                FileInputStream fis = new FileInputStream(file);
                int content;
                while ((content = fis.read()) != -1) {
                    System.out.print((char) content);
                }
                fis.close();
            } else {
                System.out.println("Access to file outside base directory is not allowed.");
            }
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        String userInput = "file.txt";
        readFile(userInput);
    }
}

